import io
import string

let input = io.read_to_end()
let lines = string.split(input, "\n")
mut i = 0
while i < lines.len()
  match lines.get(i)
  when Some(line)
    if string.contains(line, "=")
      let parts = string.split(line, "=")
      match parts.get(0)
      when Some(key)
        if string.is_empty(key)
          print("")
        else
          let total = string.len(line)
          let klen = string.len(key)
          let value = string.substring(line, klen + 1, total)
          print("#{key}:#{value}")
        end
      when None
        print("")
      end
    end
  when None
    print("")
  end
  i = i + 1
end
